function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    // Precompute teleport lists
    const teleportList: [number, number][][][] = new Array(m);
    for (let i = 0; i < m; i++) {
        teleportList[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            teleportList[i][j] = [];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const dist: number[][][] = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = new Array(k + 1).fill(Infinity);
        }
    }

    // Priority queue: [cost, i, j, t]
    const pq: [number, number, number, number][] = [];
    pq.push([0, 0, 0, 0]);
    dist[0][0][0] = 0;

    while (pq.length > 0) {
        // Sort the priority queue by cost
        pq.sort((a, b) => a[0] - b[0]);
        const [cost, i, j, t] = pq.shift()!;

        // Check if we have reached the destination
        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        // If the current cost is higher than the recorded distance, skip
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Process regular moves: right and down
        // Right move
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                pq.push([newCost, i, j + 1, t]);
            }
        }

        // Down move
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                pq.push([newCost, i + 1, j, t]);
            }
        }

        // Process teleportation moves
        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                if (dist[x][y][t + 1] > cost) {
                    dist[x][y][t + 1] = cost;
                    pq.push([cost, x, y, t + 1]);
                }
